mapper.select:


    deleted = 0
     and market_slug like concat('%', #{marketSlug}, '%')
     and event_title like concat('%', #{eventTitle}, '%')
     and market_question like concat('%', #{marketQuestion}, '%')
     and status = #{status}
     and create_time >= #{beginCreateTime}
     and create_time <= #{endCreateTime}

        and create_time between #{params.beginCreateTime} and #{params.endCreateTime}


order by id desc
